import java.util.concurrent.CompletableFuture;

// Async task chalao
CompletableFuture<String> future = CompletableFuture.supplyAsync(() -> {
    try { Thread.sleep(1000); } catch (InterruptedException e) {}
    return "Hello";
});

// Operations chain karo
future.thenApply(s -> s + " World")
      .thenApply(String::toUpperCase)
      .thenAccept(System.out::println); // Prints: HELLO WORLD

// Futures combine karo
CompletableFuture<String> f1 = CompletableFuture.supplyAsync(() -> "Hello");
CompletableFuture<String> f2 = CompletableFuture.supplyAsync(() -> "World");
CompletableFuture<String> combined = f1.thenCombine(f2,
    (s1, s2) -> s1 + " " + s2);
System.out.println(combined.get()); // "Hello World"

// Exceptions handle karo
CompletableFuture.supplyAsync(() -> {
    if (true) throw new RuntimeException("Error!");
    return "Success";
}).exceptionally(ex -> {
    System.out.println("Pakda: " + ex.getMessage());
    return "Default Value";
}).thenAccept(System.out::println);

