import java.io.*;

class Person implements Serializable {
    private static final long serialVersionUID = 1L;
    private String name;
    private int age;
    private transient String password; // Serialize nahi hoga!

    Person(String name, int age, String password) {
        this.name = name;
        this.age = age;
        this.password = password;
    }
}

// Serialize — object ko file mein likhna
try (ObjectOutputStream out = new ObjectOutputStream(
    new FileOutputStream("person.ser"))) {
    out.writeObject(new Person("Alice", 30, "secret"));
} catch (IOException e) { e.printStackTrace(); }

// Deserialize — file se object wapas lena
try (ObjectInputStream in = new ObjectInputStream(
    new FileInputStream("person.ser"))) {
    Person p = (Person) in.readObject();
    System.out.println(p.name);     // "Alice"
    System.out.println(p.password); // null (transient tha!)
} catch (IOException | ClassNotFoundException e) { e.printStackTrace(); }

