// Sirf yahi teen Shape extend kar sakte hain
sealed abstract class Shape permits Circle, Rectangle, Triangle {
    abstract double area();
}

final class Circle extends Shape {
    double radius;
    double area() { return Math.PI * radius * radius; }
}

final class Rectangle extends Shape {
    double width, height;
    double area() { return width * height; }
}

final class Triangle extends Shape {
    double base, height;
    double area() { return 0.5 * base * height; }
}

// Compiler sab subtypes jaanta hai!
String describe(Shape shape) {
    return switch (shape) {
        case Circle c    -> "Circle radius: " + c.radius;
        case Rectangle r -> "Rectangle " + r.width + "x" + r.height;
        case Triangle t  -> "Triangle base: " + t.base;
        // default ki zaroorat nahi!
    };
}
